  1→import React, { useEffect, useState, useRef } from "react";
  2→import { MoonLoader } from "react-spinners";
  3→import { motion, AnimatePresence,} from "framer-motion";
  4→import { useInfiniteQuery, useQuery } from '@tanstack/react-query';
  5→import './postcards.css';
  6→import { getJournals, searchJournals } from "../../../../API/Api";
  7→import ParseContent from "./parseData";
  8→import { useInView } from 'react-intersection-observer';
  9→import CalculateText from "./calculateReadingTime";
 10→import { useLocation, useNavigate, } from "react-router-dom";
 11→import VerifiedBadge from "../../Badge/VerifiedBadge";
 12→
 13→import { useAuth } from "../../../Context/useAuth";
 14→import { useAddViewsMutation, useBookMarkMutation, useLikeMutation } from "../../../utils/useMutation";
 15→import formatCounts from "../../../../helpers/fomatCounts";
 16→import debounce from "../../../../helpers/debounce";
 17→import { handleClickProfile, handleCLickContent } from "../../../../helpers/handleClicks";
 18→import formatPostDate from "../../../../helpers/formatDateString";
 19→import { handleImageFallback } from "../../../utils/handleImageFallback";
 20→import { getCanvasPreview } from "../../../utils/canvasDoc";
 21→
 22→
 23→const PostCards = () => {
 24→    const {session, user, openAuthModal} = useAuth();
 25→    const location = useLocation();
 26→
 27→    const navigate = useNavigate();
 28→    const modalRef = useRef(null);
 29→    const searchShellRef = useRef(null);
 30→    const timeOutRef = useRef();
 31→    const {ref, inView} = useInView({
 32→        threshold: 0,
 33→        rootMargin: '800px'
 34→    })
 35→    const [postIdSettings, setPostIdSettings] = useState('');
 36→    const [showHeaders, setShowHeaders] = useState(true);
 37→
 38→    const [bookmarkedMessage, setBookmarkedMessage] = useState('');
 39→    const [showBookmarkedMessage, setShowBookmarkedMessage] = useState(null);
 40→    const [searchInput, setSearchInput] = useState('');
 41→    const [debouncedSearchInput, setDebouncedSearchInput] = useState('');
 42→    const [committedSearchQuery, setCommittedSearchQuery] = useState('');
 43→    const [isSearchFocused, setIsSearchFocused] = useState(false);
 44→
 45→    const handleClickUserProfileOriginal = handleClickProfile(navigate);
 46→    const clickContent = handleCLickContent(navigate);
 47→
 48→    const mutateViews = useAddViewsMutation(session)
 49→
 50→    const handleClickUserProfile = (e, loggedInUserId, clickedUserId) => {
 51→        if(!session){
 52→            e.stopPropagation();
 53→            return openAuthModal();
 54→        }
 55→        handleClickUserProfileOriginal(e, loggedInUserId, clickedUserId);
 56→    }
 57→
 58→    const viewContent = (e, jsonbContent,wholeText, title, userId, name, avatar, created_at, journalId, isLiked, commentsCount, isBookmarked, likesCount, bookmarksCount, badge, postType = null, canvasDoc = null) =>{
 59→        if(!session){
 60→            e.stopPropagation();
 61→            return openAuthModal();
 62→        }
 63→        const formadata = new FormData();
 64→
 65→        formadata.append('journalId', journalId);
 66→        mutateViews.mutate(formadata);
 67→
 68→        clickContent(e, jsonbContent,wholeText, title, userId, name, avatar, created_at, journalId, isLiked, commentsCount, isBookmarked, likesCount, bookmarksCount, badge, postType, canvasDoc )
 69→    }
 70→
 71→    const header_links = [
 72→        {label: 'Writings', path: '/home'},
 73→        {label: 'Gallery', path: '/home/gallery'},
 74→        {label: 'Opinions', path: '/home/opinions'},
 75→    ]
 76→
 77→    const handleClickHeaderLinks = (path) =>{
 78→        navigate(path);
 79→    }
 80→
 81→    const handleExpandCanvas = (e, journal) => {
 82→        viewContent(
 83→            e,
 84→            journal.content,
 85→            getCanvasPreview(journal?.canvas_doc)?.wholeText || '',
 86→            journal.title,
 87→            journal.users.id,
 88→            journal.users.name,
 89→            journal.users.image_url,
 90→            journal.created_at,
 91→            journal.id,
 92→            journal.has_liked,
 93→            journal.comment_count?.[0]?.count,
 94→            journal.has_bookmarked,
 95→            journal.like_count?.[0]?.count,
 96→            journal.bookmark_count?.[0]?.count,
 97→            journal.users.badge,
 98→            journal?.post_type,
 99→            journal?.canvas_doc
100→        );
101→    }
102→
103→    const handleRemixCanvas = (e, journal) => {
104→        e.stopPropagation();
105→        if(!session){
106→            openAuthModal();
107→            return;
108→        }
109→
110→        const sourceTitle = typeof journal?.title === 'string' ? journal.title.trim() : '';
111→        const remixTitle = sourceTitle.toLowerCase().startsWith('remix:')
112→            ? sourceTitle
113→            : `Remix: ${sourceTitle || 'Canvas'}`;
114→
115→        navigate('/home', {
116→            state: {
117→                openEditor: true,
118→                editorMode: 'canvas',
119→                initialTitle: remixTitle,
120→                initialCanvasDoc: journal?.canvas_doc || null,
121→                remixSource: {
122→                    journalId: journal?.id,
123→                    authorName: journal?.users?.name || 'Unknown'
124→                }
125→            }
126→        });
127→    }
128→
129→    const cardIcons = [
130→        {
131→            likeAction: (isLiked) => (
132→                <svg className="svg-like" xmlns="http://www.w3.org/2000/svg" width="20px" height="20px" viewBox="0 0 24 24" fill="none">
133→                    <g id="style=fill">
134→                    <g id="like">
135→                    <path id="Subtract" fillRule="evenodd" clipRule="evenodd" d="M15.9977 5.63891C16.2695 4.34931 15.433 3.00969 14.2102 2.59462C13.6171 2.37633 12.9892 2.4252 12.4662 2.60499C11.9449 2.78419 11.4461 3.12142 11.1369 3.58441L11.136 3.58573L7.49506 9.00272C8.05104 9.29585 8.43005 9.87954 8.43005 10.5518V21.3018H6.91003V21.3018H16.6801C18.2938 21.3018 19.2028 20.2977 19.8943 19.202C20.6524 18.0009 21.1453 16.7211 21.5116 15.5812C21.6808 15.0546 21.8252 14.5503 21.9547 14.0984L21.9863 13.9881C22.126 13.5007 22.2457 13.0904 22.366 12.7549C22.698 11.8292 22.5933 10.9072 22.067 10.2072C21.5476 9.5166 20.7005 9.15175 19.76 9.15175H15.76C15.6702 9.15175 15.6017 9.11544 15.5599 9.06803C15.5238 9.02716 15.4831 8.95058 15.502 8.81171L15.9977 5.63891Z" fill={isLiked ? 'rgb(255, 116, 116)' : "#5e5e5eff"}/>
136→                    <path id="rec" d="M2.18005 10.6199C2.18005 10.03 2.62777 9.55176 3.18005 9.55176H6.68005C7.23234 9.55176 7.68005 10.03 7.68005 10.6199V21.3018H3.18005C2.62777 21.3018 2.18005 20.8235 2.18005 20.2336V10.6199Z" fill={isLiked ? 'rgb(255, 116, 116)' : "#5e5e5eff"}/>
137→                    </g>
138→                    </g>
139→                </svg>
140→            ),
141→
142→            className: 'like-button',
143→            action: (e, journalId, receiverId) => handleClickLike(e, journalId, receiverId),
144→            countLike: (count) => <p style={{padding:'0', margin: '0', fontSize: '0.78rem'}}>{formatCounts(count)}</p>
145→        },
146→        {
147→            label:
148→            <svg className="svg-comment" xmlns="http://www.w3.org/2000/svg" width="20px" height="20px" viewBox="0 0 24 24" fill="#5e5e5eff">
149→                <g id="style=fill">
150→                <g id="comment">
151→                <path id="Subtract" fillRule="evenodd" clipRule="evenodd" d="M11.9862 0.763672C6.07454 0.763672 1.23621 5.36133 1.23621 11.1034C1.23621 13.5057 2.10188 15.7237 3.55066 17.4735C5.46882 19.8566 8.48271 21.3843 11.8522 21.4238L11.8878 21.4367C11.9902 21.4735 12.1385 21.5265 12.3236 21.5916C12.6936 21.7216 13.2115 21.9001 13.8035 22.0941C14.9799 22.4797 16.4767 22.9358 17.6892 23.1894C18.303 23.3178 18.9306 23.1718 19.4096 22.8608C19.8872 22.5507 20.3019 22.0126 20.3019 21.3173C20.3019 20.9046 20.1354 20.4987 19.9732 20.1857C19.8007 19.8529 19.5794 19.5251 19.371 19.2448C19.2691 19.1076 19.1676 18.9782 19.0724 18.8609C21.3193 16.9815 22.7362 14.2061 22.7362 11.1034C22.7362 7.55126 20.8865 4.4319 18.073 2.58609C16.3321 1.4227 14.2426 0.763672 11.9862 0.763672ZM18.3637 6.03728C18.1546 5.67972 17.6953 5.55937 17.3377 5.76847C16.9801 5.97757 16.8598 6.43694 17.0689 6.7945C17.8131 8.0671 18.2362 9.53599 18.2362 11.1034C18.2362 12.6662 17.8138 14.1316 17.0693 15.4016C16.8598 15.7589 16.9797 16.2184 17.337 16.4279C17.6943 16.6374 18.1538 16.5175 18.3633 16.1602C19.2385 14.6673 19.7362 12.941 19.7362 11.1034C19.7362 9.26158 19.238 7.53236 18.3637 6.03728Z" fill="#5e5e5eff"/>
152→                </g>
153→                </g>
154→            </svg>,
155→            className: 'comment-button',
156→            commentAction: (e, jsonbContent, wholeText, title, userId, name, avatar, created_at, journalId, isLiked, commentsCount, isBookmarked, likeCount, bookmarkCount, badge, postType, canvasDoc) => viewContent(e, jsonbContent, wholeText, title, userId, name, avatar, created_at, journalId, isLiked, commentsCount, isBookmarked, likeCount, bookmarkCount, badge, postType, canvasDoc ),
157→            countComments: (count) => <p style={{padding: '0', margin: '0', fontSize: '0.78rem'}}>{formatCounts(count)}</p>
158→        },
159→        {
160→            checkBookrmark: (isBookmarked) => (
161→            <svg className="svg-bookmark" xmlns="http://www.w3.org/2000/svg" width="20px" height="20px" viewBox="0 0 24 24" fill="none">
162→                <g id="style=fill">
163→                    <g id="bookmark">
164→                    <path id="Subtract" fillRule="evenodd" clipRule="evenodd" d="M8 1.25C5.37665 1.25 3.25 3.37665 3.25 6V20.4648C3.25 21.7269 4.27311 22.75 5.53518 22.75C5.98634 22.75 6.42739 22.6165 6.80278 22.3662L11.3066 19.3636C11.7265 19.0837 12.2735 19.0837 12.6934 19.3636L17.1972 22.3662C17.5726 22.6165 18.0137 22.75 18.4648 22.75C19.7269 22.75 20.75 21.7269 20.75 20.4648V6C20.75 3.37665 18.6234 1.25 16 1.25H8ZM9 6.75C8.58579 6.75 8.25 7.08579 8.25 7.5C8.25 7.91421 8.58579 8.25 9 8.25H15C15.4142 8.25 15.75 7.91421 15.75 7.5C15.75 7.08579 15.4142 6.75 15 6.75H9Z" fill={isBookmarked ? "rgb(72, 208, 135)" : "#5e5e5eff"}/>
165→                    </g>
166→                </g>
167→            </svg>),
168→            className: 'bookmark-button',
169→            bookmarkAction: (e, journalId) => debounceClickBookmark(e, journalId),
170→            countBookmarks: (count) => <p  style={{padding: '0', margin: '0', fontSize: '0.78rem'}}>{formatCounts(count)}</p>
171→        },
172→        {
173→            iconCount: (count) => <p style={{padding: '0', margin: '0', fontSize: '0.6rem', color: "var(--icon-view-count)"}}>{formatCounts(count)}</p>,
174→            iconView:
175→            <svg xmlns="http://www.w3.org/2000/svg" fill="var(--icon-view)" width="28px" height="28px" viewBox="-3.5 0 32 32" version="1.1">
176→                <title>view</title>
177→                <path d="M12.406 13.844c1.188 0 2.156 0.969 2.156 2.156s-0.969 2.125-2.156 2.125-2.125-0.938-2.125-2.125 0.938-2.156 2.125-2.156zM12.406 8.531c7.063 0 12.156 6.625 12.156 6.625 0.344 0.438 0.344 1.219 0 1.656 0 0-5.094 6.625-12.156 6.625s-12.156-6.625-12.156-6.625c-0.344-0.438-0.344-1.219 0-1.656 0 0 5.094-6.625 12.156-6.625zM12.406 21.344c2.938 0 5.344-2.406 5.344-5.344s-2.406-5.344-5.344-5.344-5.344 2.406-5.344 5.344 2.406 5.344 5.344 5.344z"/>
178→            </svg>,
179→
180→        }
181→    ]
182→
183→    const userId = user?.userData?.[0]?.id || null;
184→    const isSearchMode = committedSearchQuery.length >= 2;
185→
186→    useEffect(() => {
187→        const timer = setTimeout(() => {
188→            setDebouncedSearchInput(searchInput.trim());
189→        }, 350);
190→
191→        return () => clearTimeout(timer);
192→    }, [searchInput]);
193→
194→    const {
195→        data,
196→        fetchNextPage,
197→        hasNextPage,
198→        isFetchingNextPage,
199→        isLoading: isFeedLoading,
200→    } = useInfiniteQuery({
201→        queryKey: ['journals', userId],
202→        queryFn: ({pageParam = null}) => getJournals(pageParam, 5, userId),
203→        getNextPageParam: (lastPage) => {
204→            if(lastPage?.hasMore) {
205→                const lastJournal = lastPage?.data[lastPage?.data?.length - 1]; //get the last array of object using index
206→                return new Date(lastJournal.created_at).toISOString();
207→            }
208→            return undefined;
209→        } ,
210→        refetchOnWindowFocus: false
211→    })
212→
213→    const {
214→        data: searchData,
215→        isLoading: isSearchLoading,
216→        isFetching: isSearchFetching,
217→        error: searchError,
218→    } = useQuery({
219→        queryKey: ['journals-search', userId, committedSearchQuery],
220→        queryFn: () => searchJournals(committedSearchQuery, 10, userId),
221→        enabled: isSearchMode,
222→        refetchOnWindowFocus: false,
223→        staleTime: 15 * 1000,
224→    });
225→
226→    const {
227→        data: suggestionData,
228→        isLoading: isSuggestionsLoading,
229→    } = useQuery({
230→        queryKey: ['journals-suggestions', userId, debouncedSearchInput],
231→        queryFn: () => searchJournals(debouncedSearchInput, 6, userId),
232→        enabled: debouncedSearchInput.length >= 2 && isSearchFocused,
233→        refetchOnWindowFocus: false,
234→        staleTime: 10 * 1000,
235→    });
236→
237→    const handleClickSettings = (e, postId) =>{
238→        e.stopPropagation();
239→        setPostIdSettings(postId === postIdSettings ? null : postId)
240→    }
241→
242→    const mutationLike = useLikeMutation(session, user?.userData?.[0]?.id);
243→
244→    const handleClickLike = async(e, journalId, receiverId) => {
245→        e.stopPropagation();
246→        if(!session) return openAuthModal();
247→        console.log(journalId)
248→        mutationLike.mutate({journalId, receiverId}) //passing this into mutationFn {journalId: the id}
249→    }
250→
251→
252→    const mutationBookmark = useBookMarkMutation(session, userId);
253→
254→    const handleClickBookmark = async(e, journalId,) =>{
255→        e.stopPropagation();
256→        if(!session) return openAuthModal();
257→        console.log(journalId)
258→        // mutationBookmark.mutate({journalId});
259→        const response = await mutationBookmark.mutateAsync({journalId})
260→
261→        if(timeOutRef.current){
262→            clearTimeout(timeOutRef.current);
263→        }
264→        if(response.message === 'success'){
265→            setBookmarkedMessage('Post was added to your Bookmarks')
266→            setShowBookmarkedMessage(journalId);
267→            timeOutRef.current = setTimeout(() =>{
268→                setShowBookmarkedMessage(null)
269→                setBookmarkedMessage('')
270→            }, 2500)
271→        } else {
272→            setBookmarkedMessage('Post was removed from your Bookmarks')
273→            setShowBookmarkedMessage(journalId);
274→            timeOutRef.current = setTimeout(() =>{
275→                setShowBookmarkedMessage(null)
276→                setBookmarkedMessage('')
277→            }, 2500)
278→        }
279→        console.log(response.message);
280→    }
281→
282→    const debounceClickBookmark = debounce(handleClickBookmark, 100);
283→
284→    const handleSubmitSearch = (rawQuery) => {
285→        const normalizedQuery = typeof rawQuery === 'string' ? rawQuery.trim() : '';
286→        if(normalizedQuery.length < 2){
287→            setCommittedSearchQuery('');
288→            return;
289→        }
290→
291→        setCommittedSearchQuery(normalizedQuery);
292→        setSearchInput(normalizedQuery);
293→        setIsSearchFocused(false);
294→    };
295→
296→    const handleClearSearch = () => {
297→        setSearchInput('');
298→        setDebouncedSearchInput('');
299→        setCommittedSearchQuery('');
300→        setIsSearchFocused(false);
301→    };
302→
303→    const handleSearchInputKeyDown = (e) => {
304→        if(e.key === 'Enter'){
305→            e.preventDefault();
306→            handleSubmitSearch(searchInput);
307→        }
308→
309→        if(e.key === 'Escape'){
310→            setIsSearchFocused(false);
311→        }
312→    };
313→
314→    const handleClickSuggestion = (journal) => {
315→        if(!journal?.id){
316→            return;
317→        }
318→        setIsSearchFocused(false);
319→        if(journal?.title){
320→            setSearchInput(journal.title);
321→            setDebouncedSearchInput(journal.title);
322→        }
323→        navigate(`/home/post/${journal.id}`);
324→    };
325→
326→    useEffect(() => {
327→        const handleOutsideSearchClick = (e) => {
328→            if(searchShellRef.current && !searchShellRef.current.contains(e.target)){
329→                setIsSearchFocused(false);
330→            }
331→        };
332→
333→        window.addEventListener('mousedown', handleOutsideSearchClick);
334→        return () => window.removeEventListener('mousedown', handleOutsideSearchClick);
335→    }, []);
336→
337→    useEffect(() =>{
338→        if(!isSearchMode && inView && hasNextPage && !isFetchingNextPage) {
339→            fetchNextPage();
340→        }
341→    }, [inView, fetchNextPage, hasNextPage, isFetchingNextPage, isSearchMode])
342→
343→
344→    useEffect(() => {
345→       const handleClickOutside = (e) =>{
346→        if(modalRef.current && !modalRef.current.contains(e.target)){
347→            setPostIdSettings(null)
348→        }
349→       }
350→       window.addEventListener('click', handleClickOutside)
351→
352→       return() => {
353→        window.removeEventListener('click', handleClickOutside)
354→       }
355→    }, [])
356→
357→    useEffect(() =>{
358→        const scroll = (e) =>{
359→            setShowHeaders(!showHeaders)
360→
361→            if(timeOutRef.current){
362→                clearTimeout(timeOutRef.current);
363→            }
364→            timeOutRef.current = setTimeout(() => {
365→                setShowHeaders(showHeaders)
366→            }, 100);
367→        }
368→        document.addEventListener('scroll', scroll, true);
369→        return() =>{
370→            if(timeOutRef.current){
371→                clearTimeout(timeOutRef.current);
372→            }
373→            document.removeEventListener('scroll', scroll, true)
374→        }
375→    }, [])
376→
377→    const feedJournals = data?.pages?.flatMap((page) => page.data || []) || [];
378→    const searchedJournals = searchData?.data || [];
379→    const suggestionItems = suggestionData?.data || [];
380→    const journals = isSearchMode ? searchedJournals : feedJournals;
381→    const isLoading = isSearchMode ? isSearchLoading : isFeedLoading;
382→    const showSuggestions = isSearchFocused && debouncedSearchInput.length >= 2;
383→
384→    if(isLoading) {
385→        return(
386→            <>
387→            <div className="postcards-parent-loading-container">
388→                <MoonLoader loading={isLoading} color="var(--loader-color)" speedMultiplier={1} size={20}/>
389→            </div>
390→            </>
391→        )
392→    }
393→
394→    return(
395→        <>
396→        <div className="search-shell feed-search-shell" ref={searchShellRef}>
397→        <div className="search-top-bar">
398→            <div className="search-input-wrap">
399→                <svg className="search-icon" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" aria-hidden="true">
400→                    <path d="M10 2a8 8 0 1 0 4.906 14.32l4.387 4.387a1 1 0 0 0 1.414-1.414L16.32 14.906A8 8 0 0 0 10 2Zm0 2a6 6 0 1 1 0 12a6 6 0 0 1 0-12Z"/>
401→                </svg>
402→                <input
403→                    type="search"
404→                    value={searchInput}
405→                    onChange={(e) => setSearchInput(e.target.value)}
406→                    onFocus={() => setIsSearchFocused(true)}
407→                    onKeyDown={handleSearchInputKeyDown}
408→                    placeholder="Search writings by meaning or title..."
409→                    className="search-input"
410→                    aria-label="Search journals"
411→                />
412→            </div>
413→            {searchInput ? (
414→                <button type="button" className="search-clear-btn" onClick={handleClearSearch}>
415→                    Clear
416→                </button>
417→            ) : null}
418→            {isSearchMode ? (
419→                <span className="search-mode-pill">
420→                    {isSearchFetching ? 'Searching...' : 'Matched'}
421→                </span>
422→            ) : null}
423→        </div>
424→        {showSuggestions && (
425→            <div className="search-suggestions-dropdown">
426→                {isSuggestionsLoading ? (
427→                    <div className="search-suggestion-item search-suggestion-muted">Searching...</div>
428→                ) : suggestionItems.length > 0 ? (
429→                    suggestionItems.map((item) => (
430→                        <button
431→                            key={item.id}
432→                            type="button"
433→                            className="search-suggestion-item"
434→                            onClick={() => handleClickSuggestion(item)}
435→                        >
436→                            <span className="search-suggestion-title">{item.title || 'Untitled'}</span>
437→                            <span className="search-suggestion-meta">{item?.users?.name || 'Unknown author'}</span>
438→                        </button>
439→                    ))
440→                ) : (
441→                    <div className="search-suggestion-item search-suggestion-muted">No suggestions</div>
442→                )}
443→            </div>
444→        )}
445→        </div>
446→
447→        <AnimatePresence>
448→            {!isSearchMode && showHeaders && (
449→                <motion.div
450→                className="newsfeed-header"
451→                initial={{opacity: 0}}
452→                animate={{opacity: 1, transition: {type: 'spring', stiffness: 300, damping: 25, mass: 0.8}}}
453→                exit={{ opacity: 0, y: -20,
454→                        transition: {
455→                        duration: 0.2,
456→                        ease: "easeOut"
457→                        }
458→                }}
459→                >
460→
461→                    {header_links.map((header_link, index) => (
462→                        <div key={index} className="header-links">
463→                            <div onClick={() => handleClickHeaderLinks(header_link.path) } className='header-link'>
464→                                {header_link.label}
465→                                <div className={header_link.path === location.pathname ? "header-underline" : ''}/>
466→                            </div>
467→                        </div>
468→                    ))}
469→
470→                </motion.div>
471→            )}
472→            </AnimatePresence>
473→
474→        <AnimatePresence>
475→        <div className="postcards-parent-container">
476→            {journals.length === 0 && !isLoading && (
477→                <div className="search-empty-state">
478→                    {searchError
479→                        ? 'Search failed. Please try again.'
480→                        : isSearchMode
481→                            ? 'No matching posts found.'
482→                            : 'No post available...'}
483→                </div>
484→            )}
